#include <iostream>
using namespace std;

int main() {
    int n;
    cout << "Enter size of array: ";
    cin >> n;

    // Dynamic allocation
    int* arr = new int[n];

    // Initialize array
    for (int i = 0; i < n; i++) {
        arr[i] = i * 10;
    }

    // Display elements
    cout << "Array elements: ";
    for (int i = 0; i < n; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    // Deallocate memory
    delete[] arr;

    return 0;
}

#include <iostream>
using namespace std;

int** createMatrix(int rows, int cols) {
    // Allocate array of pointers (rows)
    int** matrix = new int*[rows];

    // Allocate each row
    for (int i = 0; i < rows; i++) {
        matrix[i] = new int[cols];
    }

    // Initialize with zeros
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            matrix[i][j] = 0;
        }
    }

    return matrix;
}

void deleteMatrix(int** matrix, int rows) {
    // First delete each row
    for (int i = 0; i < rows; i++) {
        delete[] matrix[i];
    }
    // Then delete the array of pointers
    delete[] matrix;
}

int main() {
    int rows = 3, cols = 4;
    int** mat = createMatrix(rows, cols);

    // Assign values
    mat[0][0] = 1;
    mat[2][3] = 99;

    // Display
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            cout << mat[i][j] << " ";
        }
        cout << endl;
    }

    deleteMatrix(mat, rows);
    return 0;
}

#include <iostream>
#include <cstring>
using namespace std;

class String {
private:
    char* str;
    int length;

public:
    // Constructor
    String(const char* s = "") {
        length = strlen(s);
        str = new char[length + 1];
        strcpy(str, s);
    }

    // Destructor
    ~String() {
        delete[] str;
    }

    // Copy Constructor (Deep Copy)
    String(const String& s) {
        length = s.length;
        str = new char[length + 1];
        strcpy(str, s.str);
    }

    // Assignment Operator (Deep Copy)
    String& operator=(const String& s) {
        if (this != &s) {  // Check for self-assignment
            delete[] str;   // Free old memory
            length = s.length;
            str = new char[length + 1];
            strcpy(str, s.str);
        }
        return *this;
    }

    void display() {
        cout << str << endl;
    }
};

int main() {
    String s1("Hello");
    String s2 = s1;        // Copy constructor
    String s3("World");
    s3 = s1;               // Assignment operator

    s1.display();
    s2.display();
    s3.display();

    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

class Resource {
public:
    Resource() { cout << "Resource acquired\n"; }
    ~Resource() { cout << "Resource released\n"; }
    void display() { cout << "Using Resource\n"; }
};

void functionWithSmartPtr() {
    // unique_ptr automatically manages memory
    unique_ptr<Resource> ptr = make_unique<Resource>();
    ptr->display();

    // No need to call delete - automatically freed when function ends
}  // ptr goes out of scope, Resource is automatically deleted

int main() {
    cout << "Entering function\n";
    functionWithSmartPtr();
    cout << "Left function\n";

    // Example with shared_ptr
    shared_ptr<Resource> ptr1 = make_shared<Resource>();
    shared_ptr<Resource> ptr2 = ptr1;  // Reference count = 2

    cout << "Reference count: " << ptr1.use_count() << endl;

    ptr1.reset();  // Reference count = 1
    cout << "After reset, count: " << ptr2.use_count() << endl;

    return 0;
}
